parameters.jsCode:
const html = $input.first().json.data || $input.first().json.body || '';

// Keywords to filter for labor-relevant hearings
const keywords = [
  'staffing ratio',
  'collective bargaining',
  'healthcare worker',
  'wages and hours',
  'nurse staffing',
  'hospital worker',
  'sebac',
  '1199',
  'afscme',
  'labor',
  'union',
  'health care',
  'wage',
  'worker safety',
  'nursing home',
  'patient ratio'
];

// Extract hearing entries from the HTML
// The CGA page typically has tables or lists of hearings
const hearingPattern = /<tr[^>]*>([\s\S]*?)<\/tr>/gi;
const hearings = [];
let match;

while ((match = hearingPattern.exec(html)) !== null) {
  const rowHtml = match[1];
  const textContent = rowHtml.replace(/<[^>]*>/g, ' ').replace(/\s+/g, ' ').trim();

  if (textContent.length > 20) {
    const isRelevant = keywords.some(kw => 
      textContent.toLowerCase().includes(kw.toLowerCase())
    );

    if (isRelevant) {
      // Try to extract date, committee, subject from row cells
      const cells = rowHtml.match(/<td[^>]*>([\s\S]*?)<\/td>/gi) || [];
      const cellTexts = cells.map(c => c.replace(/<[^>]*>/g, '').trim());

      hearings.push({
        json: {
          raw_text: textContent,
          date: cellTexts[0] || 'Unknown',
          committee: cellTexts[1] || 'Unknown',
          subject: cellTexts[2] || textContent.substring(0, 200),
          matched_keywords: keywords.filter(kw => 
            textContent.toLowerCase().includes(kw.toLowerCase())
          )
        }
      });
    }
  }
}

// If no table-based hearings found, try a broader text-based approach
if (hearings.length === 0) {
  const fullText = html.replace(/<[^>]*>/g, ' ').replace(/\s+/g, ' ');
  const sentences = fullText.split(/[.\n]/).filter(s => s.trim().length > 20);

  for (const sentence of sentences) {
    const isRelevant = keywords.some(kw => 
      sentence.toLowerCase().includes(kw.toLowerCase())
    );
    if (isRelevant) {
      hearings.push({
        json: {
          raw_text: sentence.trim(),
          date: 'See details',
          committee: 'See details',
          subject: sentence.trim().substring(0, 200),
          matched_keywords: keywords.filter(kw => 
            sentence.toLowerCase().includes(kw.toLowerCase())
          )
        }
      });
    }
  }
}

if (hearings.length === 0) {
  return [{ json: { no_results: true, message: 'No labor-relevant hearings found this week' } }];
}

return hearings;

const items = $input.all();
const hearingsList = items.map(item => {
  return `- ${item.json.date}: ${item.json.committee} — ${item.json.subject} [Keywords: ${item.json.matched_keywords.join(', ')}]`;
}).join('\n');

return [{
  json: {
    prompt_text: hearingsList,
    hearing_count: items.length,
    items: items.map(i => i.json)
  }
}];

