const ollamaResponse = $input.first().json.response || '';
const hearingItems = $('Prepare Ollama Prompt').first().json.items || [];

const results = hearingItems.map(hearing => ({
  json: {
    title: hearing.subject,
    date: hearing.date,
    committee: hearing.committee,
    matched_keywords: hearing.matched_keywords,
    ai_summary: ollamaResponse
  }
}));

return results;
